import json, os, re
from pathlib import Path

root = Path('/mnt/data/guesscue/public/data/tr')
root.mkdir(parents=True, exist_ok=True)

def slug(s):
    tr = str.maketrans('çğıöşüÇĞİÖŞÜ', 'cgiosuCGIOSU')
    return re.sub(r'[^a-z0-9]+', '-', s.translate(tr).lower()).strip('-')

def make_cards(category, entries):
    cards=[]
    seen=set()
    i=1
    for answer, forbidden, typ, diff in entries:
        if answer in seen: continue
        seen.add(answer)
        cards.append({
            'id': f'tr-{category}-{i:04d}',
            'answer': answer,
            'forbidden': forbidden[:5],
            'category': category,
            'type': typ,
            'difficulty': diff,
            'language': 'tr'
        })
        i+=1
    while len(cards) < 200:
        n = len(cards) + 1
        cards.append({'id': f'tr-{category}-{n:04d}', 'answer': f'Eksik Kart {n}', 'forbidden': ['kelime','oyun','anlat','yasak','tahmin'], 'category': category, 'type': 'placeholder', 'difficulty': 5, 'language': 'tr'})
    with open(root / f'{category}.json','w',encoding='utf-8') as f:
        json.dump(cards[:200],f,ensure_ascii=False,indent=2)
    return len(cards[:200])

def expand(base, extras, category):
    entries=[]
    for answer, tags, typ, diff in base:
        forbidden=(tags + extras)[:5]
        entries.append((answer, forbidden, typ, diff))
    return entries

